async (page) => {
  // Eat blueberry to heal (find edible slot)
  const blueberrySlot = await page.evaluate(() => {
    const s = window.__latestGameState;
    const item = s.inventory.find(i => i.edible);
    return item ? item.slot : null;
  });

  if (blueberrySlot !== null) {
    await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), blueberrySlot);
    await page.waitForTimeout(1000);
  }

  // Run west back to Forester area - click a safe tile
  await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 220, y: 120});
  await page.waitForTimeout(5000);

  const state = await page.evaluate(() => ({
    pos: window.__latestGameState.player_position,
    hp: window.__latestGameState.player_stats.hp,
    max_hp: window.__latestGameState.player_stats.max_hp,
    logs: window.__latestGameState.inventory.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0)
  }));
  return JSON.stringify(state);
}

