async (page) => {
  // Eat apple first, then blueberry if still low
  const eatEdible = async () => {
    const slot = await page.evaluate(() => {
      const item = window.__latestGameState.inventory.find(i => i.edible);
      return item ? item.slot : null;
    });
    if (slot !== null) {
      await page.evaluate((s) => window.game.menu.getInventory().selectEdible(s), slot);
      await page.waitForTimeout(800);
    }
    return slot;
  };

  await eatEdible();
  const hp1 = await page.evaluate(() => window.__latestGameState.player_stats.hp);

  if (hp1 < 50) await eatEdible();

  // Flee north to forester area
  await page.evaluate(({x, y}) => window.__clickTile(x, y), {x: 216, y: 115});
  await page.waitForTimeout(5000);

  const state = await page.evaluate(() => ({
    pos: window.__latestGameState.player_position,
    hp: window.__latestGameState.player_stats.hp,
    max_hp: window.__latestGameState.player_stats.max_hp,
    logs: window.__latestGameState.inventory.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0),
    inventory: window.__latestGameState.inventory
  }));
  return JSON.stringify(state);
}

