async (page) => {
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);

  // Check full state including equipment
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    // Try to get equipment info
    const equipment = window.game && window.game.player ? {
      weapon: window.game.player.weaponName || window.game.player.weapon || 'unknown',
      level: window.game.player.level,
      skills: window.game.player.skills
    } : null;
    return JSON.stringify({
      pos: s.player_position,
      stats: s.player_stats,
      skills: s.skills,
      inventory: s.inventory,
      equipment
    });
  });
  return state;
}

