async (page) => {
  // Wait to see if we die
  await page.waitForTimeout(5000);

  const state = await page.evaluate(() => ({
    pos: window.__latestGameState.player_position,
    hp: window.__latestGameState.player_stats.hp,
    is_dead: window.__latestGameState.ui_state.is_dead
  }));

  if (JSON.parse(JSON.stringify(state)).is_dead) {
    return 'DEAD - need recovery';
  }

  // If alive, try to find any way to heal or escape
  const hp = state.hp;
  if (hp > 0) {
    // Try moving to any adjacent safe tile
    await page.evaluate(({x, y}) => window.__clickTile(x, y), {x: 215, y: 113});
    await page.waitForTimeout(2000);
  }

  return JSON.stringify(state);
}

