    return await page.evaluate(() => {
      const s = window.__latestGameState;
      return {x: s.player_position.x, y: s.player_position.y, hp: s.player_stats.hp};
    });
  };

  let p;
  // Keep stepping south+slightly west toward (260, 229)
  p = await step(272, 158); // south + slight west
  if (p.hp < 80) return JSON.stringify({dead: true, p});
  p = await step(268, 165);
  if (p.hp < 80) return JSON.stringify({dead: true, p});
  p = await step(265, 172);
  if (p.hp < 80) return JSON.stringify({dead: true, p});
  p = await step(263, 179);
  return JSON.stringify(p);
}

