async (page) => {
  // Check for death screen and respawn
  const isDead = await page.evaluate(() => {
    const btn = document.getElementById('respawn');
    if (btn) {
      const style = window.getComputedStyle(btn);
      return style.display !== 'none' && style.opacity !== '0';
    }
    return false;
  });
  if (isDead) {
    await page.evaluate(() => document.getElementById('respawn').click());
    await page.waitForTimeout(3000);
  }
  const pos = await page.evaluate(() => {
    const s = window.__latestGameState;
    return {x: s.player_position?.x, y: s.player_position?.y, hp: s.player_stats?.hp, isDead: s.ui_state?.is_dead};
  });
  return JSON.stringify({isDead, pos});
}

