  await page.evaluate(({x,y}) => window.__clickTile(x, y), {x: 191, y: 157});
  await page.waitForTimeout(5000);

  const s = await page.evaluate(() => window.__latestGameState);
  const pos = {x: s.player_position.x, y: s.player_position.y, hp: s.player_stats.hp};
  console.log('pos after walk:', JSON.stringify(pos));

  // Now try warp
  await page.evaluate(() => document.getElementById('warp-button').click());
  await page.waitForTimeout(1000);
  const rect = await page.evaluate(() => {
    const el = document.getElementById('warp0');
    const r = el.getBoundingClientRect();
    return {x: r.x + r.width/2, y: r.y + r.height/2, w: r.width};
  });
  console.log('warp rect:', JSON.stringify(rect));
  await page.mouse.click(rect.x, rect.y);
  await page.waitForTimeout(4000);

  const s2 = await page.evaluate(() => window.__latestGameState);
  return JSON.stringify({pos: s2.player_position, hp: s2.player_stats.hp});
}

