async (page) => {
  // Set attack style to Hack first
  await page.evaluate(() => window.game.player.setAttackStyle(0));

  const s = await page.evaluate(() => {
    const g = window.__latestGameState;
    if (!g) return null;
    return {
      pos: g.player_position,
      hp: `${g.player_stats.hp}/${g.player_stats.max_hp}`,
      inv: g.inventory.map(i => ({slot: i.slot, name: i.name, count: i.count, edible: i.edible})),
      quests: g.quests.filter(q => q.started && !q.finished).map(q => ({key: q.key, stage: q.stage}))
    };
  });
  return JSON.stringify(s, null, 2);
}

