async (page) => {
  // Navigate to Village Girl (136, 146) via hops
  // From (166, 116): hop to (152, 128), then (137, 145)
  await page.evaluate(() => window.game.player.go(152, 128));
  await page.waitForTimeout(10000);
  await page.evaluate(() => window.game.player.go(138, 145));
  await page.waitForTimeout(10000);

  const pos = await page.evaluate(() => ({x: window.game.player.gridX, y: window.game.player.gridY})).catch(() => null);
  if (!pos) return 'context destroyed';

  // Talk to Village Girl
  const vg = await page.evaluate(() => {
    const vals = Object.values(window.game.entities.entities);
    return vals.filter(e => e && e.type === 1 && e.name === 'Village Girl').map(e => ({name: e.name, x: e.gridX, y: e.gridY, id: e.instance}))[0];
  });

  if (vg) {
    const dist = Math.abs(pos.x - vg.x) + Math.abs(pos.y - vg.y);
    if (dist <= 2) {
      await page.evaluate((id) => window.__talkToNPC(id), vg.id);
      await page.waitForTimeout(1500);
    }
  }

  const dialogue = await page.evaluate(() => window.__latestGameState?.ui_state?.npc_dialogue);

  // Scan all tiles around OEC building (108-115, 146-155)
  const scanResult = await page.evaluate(() => {
    const results = [];
    for (let x = 106; x <= 118; x++) {
      for (let y = 144; y <= 157; y++) {
        const collide = window.game.map.isColliding(x, y);
        const pathLen = window.game.player.requestPathfinding(x, y).length;
        if (!collide) {
          results.push({x, y, pathLen, accessible: pathLen > 0});
        }
      }
    }
    return results;
  });

  const accessible = scanResult.filter(t => t.accessible);
  const inaccessible = scanResult.filter(t => !t.accessible);

  return JSON.stringify({pos, vgDist: vg ? Math.abs(pos.x-vg.x)+Math.abs(pos.y-vg.y) : 'N/A', dialogue, accessible: accessible.slice(0,10), inaccessible: inaccessible.slice(0,10)});
}

