async (page) => {
  // Check tile IDs around current position to find doors/portals
  const result = await page.evaluate(() => {
    const p = window.game.player;
    const map = window.game.map;
    const px = p.gridX, py = p.gridY;
    const tiles = {};
    for (let dy = -5; dy <= 5; dy++) {
      for (let dx = -5; dx <= 5; dx++) {
        const x = px + dx, y = py + dy;
        const idx = y * map.width + x;
        const tileId = map.data[idx];
        if (tileId && tileId !== 0) {
          tiles[`${x},${y}`] = tileId;
        }
      }
    }
    return JSON.stringify({ pos: {x: px, y: py}, tiles_nonzero: tiles });
  });
  return result;
}

