    const px = p.gridX, py = p.gridY;
    const result = [];
    // Look for cave tiles (3458) and door tiles (1751) on south coast
    for (let y = py - 20; y <= py + 20; y++) {
      for (let x = px - 30; x <= px + 30; x++) {
        const idx = y * map.width + x;
        const tileData = map.data[idx];
        const tiles = Array.isArray(tileData) ? tileData : [tileData];
        if (tiles.includes(3458) || tiles.includes(1751)) {
          result.push({x, y, tiles});
        }
      }
    }
    return result;
  });

  const asciiMap = await page.evaluate(() => {
    const m = window.__latestAsciiMap;
    return m && !m.error ? m.legendText : '';
  });

  return JSON.stringify({ pos, caves, nearby_entities: asciiMap });
}

