async (page) => {
  let kills = 0;

  // Kill crabs in a loop - 10 needed for achievement
  for (let i = 0; i < 12; i++) {
    // Find nearest crab
    const crabLabel = await page.evaluate(() => {
      const m = window.__latestAsciiMap;
      if (!m || m.error) return null;
      // Find first Crab in legend
      const lines = m.legendText.split('\n');
      for (const line of lines) {
        if (line.includes('[C]') && line.includes('Crab')) {
          const match = line.match(/E\d+/);
          return match ? match[0] : null;
        }
      }
      return null;
    });

    if (!crabLabel) {
      await page.waitForTimeout(3000);
      continue;
    }

    const result = await page.evaluate((label) => window.__clickEntity(label), crabLabel);
    await page.waitForTimeout(7000); // Wait for fight to finish

    const hp = await page.evaluate(() => window.__latestGameState?.player_stats?.hp);
    const isDead = await page.evaluate(() => window.__latestGameState?.ui_state?.is_dead);
    if (isDead) { kills = -1; break; }

    // Heal if needed
    if (hp < 150) {
      const food = await page.evaluate(() => {
        const inv = window.__latestGameState?.inventory || [];
        return inv.find(i => i.edible);
      });
      if (food) {
        await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), food.slot);
        await page.waitForTimeout(500);
      }
    }

    kills++;
  }

  const pos = await page.evaluate(() => ({ x: window.game.player.gridX, y: window.game.player.gridY }));
  const hp = await page.evaluate(() => window.__latestGameState?.player_stats?.hp);
  return JSON.stringify({ kills, pos, hp });
}

